export async function generateImage(
  prompt: string,
  options: { width?: number; height?: number; steps?: number; seed?: number } = {}
): Promise<{ image: string; seed: number }> {
  // Отдельный ключ для генерации изображений (FLUX.1)
  const apiKey = process.env.NVIDIA_IMAGE_API_KEY || process.env.NVIDIA_API_KEY
  if (!apiKey) throw new Error('NVIDIA API key not configured for image generation')

  const { width = 1024, height = 1024, steps = 4, seed = 0 } = options

  console.log(`[NVIDIA Image] Generating: "${prompt.slice(0, 50)}..."`)

  const res = await fetch('https://ai.api.nvidia.com/v1/genai/black-forest-labs/flux.1-schnell', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${apiKey}`,
      'Accept': 'application/json',
    },
    body: JSON.stringify({ prompt, width, height, steps, seed }),
  })

  if (!res.ok) throw new Error(`NVIDIA Image: ${res.status} ${await res.text()}`)

  const data = await res.json()
  const image = data.artifacts?.[0]?.base64 || data.image || ''
  const resultSeed = data.artifacts?.[0]?.seed ?? seed

  if (!image) throw new Error('NVIDIA Image: no image in response')

  console.log(`[NVIDIA Image] Success, seed: ${resultSeed}`)
  return { image, seed: resultSeed }
}

