  let match: RegExpExecArray | null

  while ((match = sectionRegex.exec(markdown)) !== null) {
    sections.push({ title: match[1].trim(), index: match.index })
  }

  if (sections.length === 0) {
    console.log('[Images] No sections found, skipping')
    return markdown
  }

  // Выбираем секции для иллюстраций: берём равномерно распределённые
  const step = Math.max(1, Math.floor(sections.length / MAX_IMAGES_PER_LESSON))
  const selectedSections = sections.filter((_, i) => i % step === 0).slice(0, MAX_IMAGES_PER_LESSON)

  // Генерируем изображения параллельно
  const imageResults = await Promise.allSettled(
    selectedSections.map(async (section) => {
      // Формируем промпт для изображения на основе темы и секции
      const imagePrompt = buildImagePrompt(analysis.topic, section.title, analysis.domain)
      console.log(`[Images] Generating for "${section.title}": "${imagePrompt.slice(0, 80)}..."`)

      const result = await generateImage(imagePrompt, {
        width: 1024,
        height: 576, // 16:9 для лучшего отображения в теории
        steps: 4
      })
      return { section, image: result.image }
    })
  )

  // Вставляем изображения в markdown (идём с конца, чтобы не сбивать индексы)
  let enriched = markdown
  const successfulImages = imageResults
    .map((r, i) => r.status === 'fulfilled' ? r.value : null)
    .filter(Boolean) as { section: { title: string; index: number }; image: string }[]

  // Сортируем по позиции в тексте (с конца)
  successfulImages.sort((a, b) => b.section.index - a.section.index)

  for (const { section, image } of successfulImages) {
    // Находим конец строки заголовка
    const headingEnd = enriched.indexOf('\n', section.index)
    if (headingEnd === -1) continue

    const imageMarkdown = `\n\n![Иллюстрация: ${section.title}](data:image/png;base64,${image})\n`
    enriched = enriched.slice(0, headingEnd + 1) + imageMarkdown + enriched.slice(headingEnd + 1)
  }

  console.log(`[Images] Successfully added ${successfulImages.length}/${selectedSections.length} illustrations`)
  return enriched
}

/** Формирует промпт для генерации иллюстрации к секции теории */
function buildImagePrompt(topic: string, sectionTitle: string, domain: DomainType): string {
  const domainStyles: Record<DomainType, string> = {
    physics: 'scientific diagram, physics visualization, clean technical illustration',
    math: 'mathematical visualization, geometric shapes, clean diagram',
    chemistry: 'molecular structure, chemical diagram, laboratory illustration',
    programming: 'code architecture diagram, technology illustration, digital art',
    biology: 'biological illustration, cell diagram, nature visualization',
    history: 'historical illustration, vintage style, educational artwork',
    economics: 'business infographic, economic chart visualization, professional',
    languages: 'language learning illustration, cultural symbols, educational',
    psychology: 'brain visualization, cognitive diagram, human behavior illustration',
    law: 'legal concept illustration, justice symbols, professional diagram',
    medicine: 'medical illustration, anatomy diagram, healthcare visualization',
    art: 'artistic illustration, creative visualization, fine art style',
    general: 'educational illustration, clean infographic, professional diagram'
  }

  const style = domainStyles[domain] || domainStyles.general
  return `Educational illustration for "${sectionTitle}" in the topic "${topic}". Style: ${style}. Clean, modern, minimalist design with soft colors. No text or labels on the image.`
}

