// NVIDIA NIM конфигурация
// Стратегия: NVIDIA Nemotron модели = приоритет на серверах, меньше очередей
const NVIDIA_BASE_URL = 'https://integrate.api.nvidia.com/v1'
const NVIDIA_MODELS = {
  // 🧠 Генерация теории — 253B, топ reasoning/math/coding, приоритет NVIDIA
  heavy: 'nvidia/llama-3.1-nemotron-ultra-253b-v1',
  // 💬 Чат с AI-наставником — 49B, быстрый + точный, приоритет NVIDIA
  chat: 'nvidia/llama-3.3-nemotron-super-49b-v1.5',
  // 🤖 Агентные задачи — 235B MoE, reasoning, менее хайповая чем DeepSeek
  agentic: 'qwen/qwen3-235b-a22b',
  // ⚡ Быстрые задачи на NVIDIA — 9B hybrid Transformer-Mamba, мгновенный
  fast: 'nvidia/nvidia-nemotron-nano-9b-v2',
  // 🛡️ Надёжный fallback — проверенный, стабильный
  fallback: 'meta/llama-3.3-70b-instruct',
  // 💻 Code review
  code: 'qwen/qwen2.5-coder-32b-instruct',
