  agentic: ['nvidia', 'groq'],              // 🤖 NVIDIA Step Flash → Groq fallback
}

  switch (taskType) {
    case 'heavy':   return NVIDIA_MODELS.heavy    // DeepSeek V3.2 685B — генерация теории
