    case 'agentic': return NVIDIA_MODELS.agentic   // Step 3.5 Flash 200B — агентные задачи
    case 'fast':    return NVIDIA_MODELS.fast       // Step 3.5 Flash — быстрые задачи
    default:        return NVIDIA_MODELS.fallback   // Llama 3.3 70B — надёжный fallback
  }
}

async function generateNvidia(
  system: string,
  user: string,
  options: GenerateOptions
): Promise<{ content: string; tool_calls?: any[] }> {
